<template>
  <!-- 父容器 -->
  <el-container>
    <!--  头部信息  -->
    <el-header class="flex animate__animated animate__slideInDown">
      <div class="logo flex">NAIHE</div>
      <div class="fun flex">
        <ol class="flex nav">
          <li class="anchor"></li>
          <li v-for="item in navArr" :key="item.id" :data-title="item.data"><i
              :class="item.class" :style="'color:' + item.color + ';'"></i>{{ item.context }}
          </li>
        </ol>
      </div>
    </el-header>
    <!--  内容区域  -->
    <router-view/>
    <!--  底部信息  -->
    <el-footer class="animate__animated animate__slideInUp">
      &copy;
      <el-link class="website-year" disabled>2022~</el-link>
      <el-link class="website-author" href="mailto:naiheemail@yeah.net" type="info">@Naihe</el-link>
      &emsp;
      <el-link class="copyright">All Rights Reserved</el-link>
    </el-footer>

    <!--  气泡盒子  -->
    <div class="bubbles" data-num="9" data-time="8">
      <ol>
        <li v-for="item in 9" :key="item" class="bubble"></li>
      </ol>
    </div>

    <!--  浮动工具盒  -->
    <div class="boxTools">
      <div class="tool-button backToTop animate__animated" @click="backToTop">
        <i class="ri-rocket-line"></i>
      </div>
      <div class="tool-button">
        <i class="ri-sun-line"></i>
      </div>
      <div class="tool-button">
        <i class="ri-settings-4-line"></i>
      </div>
    </div>
  </el-container>
</template>

<script>
import $ from 'jquery'

export default {
  name: "Blog",
  data: () => ({
    navArr: [
      {
        id: 1,
        data: 'life',
        context: '咬文嚼字',
        class: 'ri-time-fill',
        color: '#63e6be'
      },
      {
        id: 2,
        data: 'money',
        context: '不务正业',
        class: 'ri-money-cny-box-fill',
        color: '#ffec99'
      },
      {
        id: 3,
        data: 'images',
        context: '美轮美奂',
        class: 'ri-image-2-fill',
        color: 'pink'
      }
    ]
  }),
  mounted() {
    this.navAnimate()
    this.eventBinding()
  },
  methods: {
    navAnimate() {
      sessionStorage.setItem('offLeft', $('.anchor')[0].offsetLeft)
      const tempPath = sessionStorage.getItem('tempPath')
      if (!tempPath) {
        $('.anchor').hide()
        sessionStorage.setItem('offLeft', '0')
      } else {
        $('.anchor').show()
      }
      if (!!tempPath) {
        const x = $(document.querySelector(`li[data-title=${tempPath}]`))[0].offsetLeft
        sessionStorage.setItem('offLeft', x)
      }
      if (!!sessionStorage.getItem('offLeft')) {
        $('.anchor').css('left', `${sessionStorage.getItem('offLeft')}px`)
      }
      // 获取设备宽度
      if (window.innerWidth > 1200) {
        $('.nav li').not('li[class=anchor]').mouseover(function () {
          $('.anchor').show().css('left', $(this)[0].offsetLeft)
          $(this).css({'background-color': 'transparent', 'color': '#f6bec8'})
        }).mouseout(function () {
          $(this).css({'color': '#475669'})
          if (!tempPath) {
            $('.anchor').css('left', '-100px')
          } else {
            $('.anchor').css('left', `${sessionStorage.getItem('offLeft')}px`)
          }
        })
      }
    },
    eventBinding() {
      let that = this
      $('.nav li').click(function (event) {
        sessionStorage.setItem('offLeft', $('.anchor')[0].offsetLeft)
        that.$router.push({
          path: event.currentTarget.dataset.title
        })
      })
      $('.logo').click(function () {
        $('.anchor').css('left', '-100px')
        sessionStorage.setItem('offLeft', '-100')
        that.$router.replace({
          path: '/'
        })
      })
      $('.backToTop').hide()
      $('main').scroll(function () {
        if (document.querySelector('main').scrollTop >= 100) {
          $('.backToTop').removeClass('animate__backOutUp').show().addClass('animate__backInDown')
        } else {
          $('.backToTop').removeClass('animate__backInDown').addClass('animate__backOutUp')
        }
      })
    },
    backToTop() {
      if (document.querySelector('main').scrollTop >= 100) {
        document.querySelector('main').scrollTo(0, 0)
      }
    }
  }
}
</script>

<style scoped>

/* 顶部信息 */
.el-header {
  color: #ffffff;
  height: 60px;
  line-height: 60px;
  letter-spacing: 8px;
  border-bottom: 1px solid #ffffff24;
  transition: 0.5s;
}

/* logo */
.logo {
  justify-content: center;
  flex: 1;
  cursor: progress;
}

/* 导航栏 */
.fun {
  flex: 8;
  padding-left: 8px;
}

/* 内容显示区域 */
.el-main {
  overflow: hidden;
  overflow-y: scroll;
  background-color: transparent;
  display: flex;
  justify-content: space-evenly;
  flex-flow: wrap;
  padding: 50px !important;
}

/* 底部信息 */
.el-footer {
  background-color: #00000024;
  text-align: center;
  height: 60px;
  line-height: 60px;
  transition: 2s;
  user-select: none;
}

.el-footer:hover {
  background-color: #00000048;
}

/* 作者 */
.website-author {
  cursor: help;
}

/* 版权 */
.copyright:hover {
  color: #606266 !important;
  cursor: text;
}

.website-year {
  margin: auto 8px;
  cursor: text;
  color: #606266 !important;
}

.website-year:hover {
  color: #606266 !important;
}

/* 导航 */
.nav {
  letter-spacing: normal;
}

.nav li {
  margin-right: 18px;
  cursor: pointer;
  color: #475669;
  width: 100px;
  font-size: smaller;
  padding: 0 8px;
  text-align: center;
  transition: 1s;
}

.nav li:hover {
  background-color: #ffffff24;
  font-size: unset;
}

.nav-rotate {
  transform: rotateX(360deg);
}

/* 浮动工具盒 */
.boxTools {
  position: fixed;
  bottom: 90px;
  right: 10px;
  z-index: 3;
}

.tool-button {
  color: #909399;
  width: 34px;
  height: 34px;
  line-height: 34px;
  text-align: center;
  border-radius: 8px;
  cursor: pointer;
  margin: 5px auto 3px;
  background: -webkit-gradient(linear, left top, left bottom, from(#34425a), to(#222e3e));
  text-shadow: 0 1px #ffffff00;
  transition: .25s;
}

.tool-button:hover {
  color: #e9e9eb;
}

i[class^="ri-"] {
  vertical-align: middle;
  font-size: 16px;
}
</style>
